B.Rc=new A.k(2001,11,2,"\uc560\ub2c8\uba54\uc774\uc158","\ud53d\uc0ac '\ubaac\uc2a4\ud130 \uc8fc\uc2dd\ud68c\uc0ac' \uac1c\ubd09","\ud53d\uc0ac\uc758 \uc0c8 3D \uc560\ub2c8\uba54\uc774\uc158\uc774 \uac1c\ubd09\ud574 \ud765\ud589\uc5d0 \uc131\uacf5\ud588\ub2e4. \uc560\ub2c8\uba54\uc774\uc158 \uc0b0\uc5c5\uc758 \uc8fc\ub3c4\uad8c \uacbd\uc7c1\uc774 \ub728\uac81\ub2e4.","\ud788\ud2b8 \ucf58\ud150\uce20\ub294 \ub450\uace0\ub450\uace0 \ub3c8\uc744 \ubc84\ub294 \uc9c0\uc2dd\uc7ac\uc0b0\uc785\ub2c8\ub2e4.",B.w)
